%[DOCS AUTOGENERATED]
function move_results_to_pubs(pub_to_move)
% Function move_results_to_pubs
%
% :param pub_to_move: pub_to_move

    if nargin==0
        pub_to_move = {'RE','AOR'};
    end
    if any(contains(pub_to_move,'RE'))
        move_RE = true;
    else
        move_RE = false;
    end
    if any(contains(pub_to_move,'AOR'))
        move_AOR = true;
    else
        move_AOR = false;
    end

    [figs_in_RE, figs_in_AOR, tabs_in_RE, tabs_in_AOR] = fig_tab_pub_mapping();

    RE =  'pubs/renewable-energy-mdo';
    AOR = 'pubs/applied-ocean-research-model';

    success = true;

    if move_RE
        for i = 1:length(figs_in_RE)
            success_i = copy_result(figs_in_RE{i}, '.pdf', [RE '/figs/from-matlab']);
            success = success && success_i;
        end
        for i = 1:length(tabs_in_RE)
            success_i = copy_result(tabs_in_RE{i}, '.tex', [RE '/tables/from-matlab']);
            success = success && success_i;
        end
    end
    if move_AOR
        for i = 1:length(figs_in_AOR)
            success_i = copy_result(figs_in_AOR{i}, '.pdf', [AOR '/figs/from-matlab']);
            success = success && success_i;
        end
        for i = 1:length(tabs_in_AOR)
            success_i = copy_result(tabs_in_AOR{i}, '.tex', [AOR '/tables/from-matlab']);
            success = success && success_i;
        end
    end
    %assert(success, 'Some files were not found and could not be copied.')
end

function success = copy_result(class_dot_description, extension, dest_folder)
    
    s = split(class_dot_description, '.');
    class_name = s{1};
    if strcmp(class_name, 'Tikz')
        success = true;
    else
        fig_tab_desc = s{2};
        src = fullfile('results', class_name, [fig_tab_desc, extension]);
        dest = fullfile(dest_folder, [fig_tab_desc, extension]);
        if isfile(src)
            if ~isfolder(dest_folder)
                mkdir(dest_folder);
            end
            copyfile(src, dest);
            success = true;
        else
            warning(['File not found: ' src])
            success = false;
        end
    end
end